class Solution {
public:
    vector<bool> canMakePalindromeQueries(string s, vector<vector<int>>& queries) {
        int n = s.size();
        vector<int> left(n / 2 + 1), right(n / 2 + 1);
        for (int i = 0; i < n / 2; i++) {
            left[i + 1] = left[i] + (s[i] == s[n - i - 1] ? 0 : 1);
        }
        for (int i = n / 2; i < n; i++) {
            right[i - n / 2 + 1] = right[i - n / 2] + (s[i] == s[n - i - 1] ? 0 : 1);
        }
        vector<bool> ans(queries.size());
        for (int i = 0; i < queries.size(); i++) {
            int a = queries[i][0], b = queries[i][1], c = queries[i][2], d = queries[i][3];
            ans[i] = (left[b + 1] - left[a] + right[d + 1] - right[c] <= 1);
        }
        return ans;
    }
};
